import type * as React from 'react';

import {cn} from '@/lib/utils';

/**
 * A visually hidden skip navigation link that becomes visible on focus.
 * Place this as the first element inside `<body>` to satisfy WCAG 2.4.1 Bypass Blocks.
 *
 * ### Component Props
 *
 * Accepts all standard `<a>` HTML element props, plus:
 *
 * | Prop   | Type     | Default                   |
 * | :----- | :------- | :------------------------ |
 * | _href_ | `string` | required                  |
 *
 * ### Example Usage
 *
 * ```tsx
 * <SkipNav href="#main-content">Skip to main content</SkipNav>
 * <nav>...</nav>
 * <main id="main-content">...</main>
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 2.4.1 Bypass Blocks — provides a keyboard shortcut to skip repeated navigation blocks.
 * @wcag 2.4.7 Focus Visible — the link becomes visible when focused via `focus-visible:not-sr-only` and the `:focus-visible` pseudo-class.
 */
function SkipNav({
  href,
  className,
  children = 'Skip to main content',
  ...props
}: React.ComponentProps<'a'> & {href: string}) {
  return (
    <a
      href={href}
      data-slot="skip-nav"
      className={cn(
        'sr-only focus-visible:not-sr-only focus-visible:absolute focus-visible:top-4 focus-visible:left-4 focus-visible:z-toast',
        'rounded bg-background px-4 py-2 text-sm font-label text-foreground',
        'focus-visible:ring-3 focus-visible:ring-ring focus-visible:outline-none',
        className
      )}
      {...props}
    >
      {children}
    </a>
  );
}

export {SkipNav};
